  async function refreshIfExpired(token: string) {
    const decoded = jwt.verify(token, SECRET);
    if (decoded.exp < Date.now() / 1000 + 300) {
      const newToken = jwt.sign({ userId: decoded.userId }, SECRET, { expiresIn: '1h' });
      await db.tokens.update({ old: token }, { new: newToken });
      return newToken;
    }
    return token;
  }

